#!/usr/bin/env python3
import os
import json
import argparse
import logging
from typing import Dict, List, Any, Set, Tuple
import spacy
import numpy as np
import pandas as pd
from collections import defaultdict

from gpu_utils import GPUVerifier

# Initialize GPU verification
gpu_verifier = GPUVerifier(require_gpu=True)

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger("RAG-Evaluator")

class ResponseQualityEvaluator:
    """Evaluates the quality of responses generated by RAG systems."""
    
    def __init__(self, spacy_model="en_core_web_md", use_gpu=False):
        self.logger = logger
        
        # Load spaCy model
        try:
            if use_gpu:
                spacy.prefer_gpu()
            self.nlp = spacy.load(spacy_model)
            self.logger.info(f"Loaded spaCy model: {spacy_model}")
        except Exception as e:
            self.logger.error(f"Error loading spaCy model: {str(e)}")
            raise
    
    def load_ground_truth(self, gt_file: str) -> Dict[str, str]:
        """Load ground truth answers."""
        try:
            with open(gt_file, 'r', encoding='utf-8') as f:
                gt_data = json.load(f)
            
            ground_truth = {}
            for query_id, query_data in gt_data.items():
                if isinstance(query_data, dict) and "answer" in query_data:
                    ground_truth[query_id] = query_data["answer"]
                else:
                    ground_truth[query_id] = query_data
            
            self.logger.info(f"Loaded {len(ground_truth)} ground truth answers from {gt_file}")
            return ground_truth
        
        except Exception as e:
            self.logger.error(f"Error loading ground truth: {str(e)}")
            return {}
    
    def load_answers(self, answers_dir: str) -> Dict[str, Dict[str, str]]:
        """Load generated answers."""
        answers = {}
        
        try:
            answer_files = [f for f in os.listdir(answers_dir) if f.endswith("_answers.json")]
            
            for file_name in answer_files:
                file_path = os.path.join(answers_dir, file_name)
                
                with open(file_path, 'r', encoding='utf-8') as f:
                    answer_data = json.load(f)
                
                retriever_name = answer_data.get("retriever_name", file_name.replace("_answers.json", ""))
                
                retriever_answers = {}
                for query_id, query_data in answer_data.get("answers", {}).items():
                    if isinstance(query_data, dict) and "answer" in query_data:
                        retriever_answers[query_id] = query_data["answer"]
                
                answers[retriever_name] = retriever_answers
                self.logger.info(f"Loaded {len(retriever_answers)} answers for {retriever_name}")
            
            return answers
        
        except Exception as e:
            self.logger.error(f"Error loading answers: {str(e)}")
            return {}
    
    def load_retrieval_results(self, retrieval_dir: str) -> Dict[str, Dict[str, List[Dict[str, Any]]]]:
        """Load retrieval results."""
        retrieval_results = {}
        
        try:
            retrieval_files = [f for f in os.listdir(retrieval_dir) if f.endswith("_retrieval.json")]
            
            for file_name in retrieval_files:
                file_path = os.path.join(retrieval_dir, file_name)
                
                with open(file_path, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                
                retriever_name = data.get("run_info", {}).get("retriever_name", file_name.replace("_retrieval.json", ""))
                
                retriever_chunks = {}
                for query_id, query_data in data.get("queries", {}).items():
                    chunks = query_data.get("retrieved_chunks", [])
                    retriever_chunks[query_id] = chunks
                
                retrieval_results[retriever_name] = retriever_chunks
                
                total_chunks = sum(len(chunks) for chunks in retriever_chunks.values())
                avg_chunks = total_chunks / len(retriever_chunks) if retriever_chunks else 0
                self.logger.info(f"Loaded {total_chunks} chunks for {retriever_name} (avg: {avg_chunks:.2f} per query)")
            
            return retrieval_results
        
        except Exception as e:
            self.logger.error(f"Error loading retrieval results: {str(e)}")
            return {}
    
    def extract_entities(self, text: str) -> Set[str]:
        """Extract entities from text for comparison."""
        if not text or not text.strip():
            return set()
        
        doc = self.nlp(text)
        
        entities = set()
        
        # Named entities
        for ent in doc.ents:
            entities.add(ent.text.lower())
        
        # Noun chunks
        for chunk in doc.noun_chunks:
            entities.add(chunk.text.lower())
        
        # Important tokens (nouns, verbs, adjectives, numbers)
        for token in doc:
            if token.pos_ in {"NOUN", "PROPN", "VERB", "ADJ", "NUM"} and not token.is_stop:
                entities.add(token.text.lower())
        
        return entities
    
    def calculate_faithfulness(self, response: str, chunks: List[Dict[str, Any]], top_k: int = None) -> Tuple[float, Dict[str, Any]]:
        """Calculate faithfulness score (percentage of response supported by chunks)."""
        if not response or not chunks:
            return 0.0, {"error": "Empty response or chunks"}
        
        # Limit to top_k chunks if specified
        if top_k is not None:
            chunks = chunks[:top_k]
        
        # Extract entities from response and chunks
        response_entities = self.extract_entities(response)
        
        # Combine all chunks' text
        chunk_texts = [chunk.get("text", "") for chunk in chunks if chunk.get("text")]
        combined_chunk_text = " ".join(chunk_texts)
        
        # Extract entities from combined chunks
        chunk_entities = self.extract_entities(combined_chunk_text)
        
        # Calculate faithfulness score (what portion of response entities are in chunks)
        if not response_entities:
            return 1.0, {"empty_response": True}
            
        overlap = chunk_entities.intersection(response_entities)
        faithfulness = len(overlap) / len(chunk_entities)
        
        # Prepare details dictionary
        details = {
            "response_entity_count": len(response_entities),
            "chunk_entity_count": len(chunk_entities),
            "overlap_entity_count": len(overlap),
            "chunk_count": len(chunks),
            "chunk_text_lengths": [len(text) for text in chunk_texts],
            "response_length": len(response)
        }
        
        return faithfulness, details
    
    def calculate_accuracy(self, response: str, ground_truth: str) -> Tuple[float, Dict[str, Any]]:
        """Calculate accuracy score (percentage of response that matches ground truth)."""
        if not response or not ground_truth:
            return 0.0, {"error": "Empty response or ground truth"}
        
        # Extract entities from response and ground truth
        response_entities = self.extract_entities(response)
        gt_entities = self.extract_entities(ground_truth)
        
        # Calculate accuracy score (F1-like measure)
        if not response_entities:
            return 0.0, {"empty_response": True}
            
        if not gt_entities:
            return 0.0, {"empty_ground_truth": True}
            
        # Calculate overlap
        overlap = response_entities.intersection(gt_entities)
        
        # Calculate precision and recall
        precision = len(overlap) / len(response_entities)
        recall = len(overlap) / len(gt_entities)

        overlap = gt_entities.intersection(response_entities)
        
        # Calculate precision and recall
        precision = len(overlap) / len(gt_entities)
        recall = len(overlap) / len(response_entities)
        
        # Calculate F1
        accuracy = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0
        
        # Prepare details dictionary
        details = {
            "response_entity_count": len(response_entities),
            "gt_entity_count": len(gt_entities),
            "overlap_entity_count": len(overlap),
            "precision": precision,
            "recall": recall
        }
        
        return accuracy, details
    
    def evaluate_retriever(self, 
                         retriever_name: str, 
                         answers: Dict[str, str], 
                         retrieval_results: Dict[str, List[Dict[str, Any]]], 
                         ground_truth: Dict[str, str],
                         top_k: int = None) -> Dict[str, Any]:
        """Evaluate a single retriever."""
        self.logger.info(f"Evaluating {retriever_name} with top_k={top_k if top_k is not None else 'all'}")
        
        # Initialize results
        results = {
            "retriever_name": retriever_name,
            "query_count": 0,
            "avg_faithfulness": 0.0,
            "avg_accuracy": 0.0,
            "query_results": {}
        }
        
        total_faithfulness = 0.0
        total_accuracy = 0.0
        
        # Process each query
        for query_id in answers:
            # Skip if missing data
            if query_id not in retrieval_results or query_id not in ground_truth:
                self.logger.warning(f"Skipping query {query_id} due to missing data")
                continue
            
            answer = answers[query_id]
            chunks = retrieval_results[query_id]
            gt = ground_truth[query_id]
            
            # Log debugging info
            self.logger.info(f"Query {query_id}: {len(chunks)} chunks available")
            self.logger.info(f"GT length: {len(gt)}, Answer length: {len(answer)}")
            
            # Calculate faithfulness
            faithfulness, faith_details = self.calculate_faithfulness(answer, chunks, top_k)
            
            # Calculate accuracy
            accuracy, acc_details = self.calculate_accuracy(answer, gt)
            
            # Store query results
            results["query_results"][query_id] = {
                "faithfulness": faithfulness,
                "accuracy": accuracy,
                "faithfulness_details": faith_details,
                "accuracy_details": acc_details
            }
            
            # Update totals
            results["query_count"] += 1
            total_faithfulness += faithfulness
            total_accuracy += accuracy
            
            # Log query results
            self.logger.info(f"Query {query_id} - Faithfulness: {faithfulness:.4f}, Accuracy: {accuracy:.4f}")
        
        # Calculate averages
        if results["query_count"] > 0:
            results["avg_faithfulness"] = total_faithfulness / results["query_count"]
            results["avg_accuracy"] = total_accuracy / results["query_count"]
        
        self.logger.info(f"Evaluated {results['query_count']} queries for {retriever_name}:")
        self.logger.info(f"  Avg Faithfulness: {results['avg_faithfulness']:.4f}")
        self.logger.info(f"  Avg Accuracy: {results['avg_accuracy']:.4f}")
        
        return results
    
    def compare_retrievers(self, evaluation_results: Dict[str, Dict[str, Any]]) -> Dict[str, Any]:
        """Compare multiple retrievers based on evaluation results."""
        if not evaluation_results:
            return {}
        
        # Extract retriever names and scores
        retrievers = []
        faithfulness_scores = []
        accuracy_scores = []
        
        for retriever_name, results in evaluation_results.items():
            retrievers.append(retriever_name)
            faithfulness_scores.append(results["avg_faithfulness"])
            accuracy_scores.append(results["avg_accuracy"])
        
        # Create comparison dictionary
        comparison = {
            "retrievers": retrievers,
            "faithfulness": dict(zip(retrievers, faithfulness_scores)),
            "accuracy": dict(zip(retrievers, accuracy_scores)),
            "combined": {}
        }
        
        # Calculate combined score
        for retriever, faith_score, acc_score in zip(retrievers, faithfulness_scores, accuracy_scores):
            combined = (faith_score + acc_score) / 2
            comparison["combined"][retriever] = combined
        
        return comparison

def create_comparison_tables(comparison: Dict[str, Any], output_dir: str):
    """Create comparison tables between different retrievers."""
    # Create data for table
    table_data = []
    for retriever in comparison["retrievers"]:
        # Extract chunking and embedding type
        if "(" in retriever and ")" in retriever:
            chunking = retriever.split("(")[1].split(")")[0]
        else:
            chunking = "unknown"
            
        if "Content" in retriever:
            embedding = "content"
        elif "TF-IDF" in retriever:
            embedding = "tfidf"
        elif "Prefix" in retriever:
            embedding = "prefix"
        elif "Reranker" in retriever:
            if "TFIDF" in retriever:
                embedding = "reranker_tfidf"
            elif "Prefix" in retriever:
                embedding = "reranker_prefix"
            else:
                embedding = "reranker"
        else:
            embedding = "unknown"
        
        # Add to data
        table_data.append({
            "retriever": retriever,
            "chunking": chunking,
            "embedding": embedding,
            "faithfulness": comparison["faithfulness"][retriever],
            "accuracy": comparison["accuracy"][retriever],
            "combined": comparison["combined"][retriever]
        })
    
    # Create DataFrame
    df = pd.DataFrame(table_data)
    
    # Save full table
    full_table_path = os.path.join(output_dir, "retriever_comparison_table.csv")
    df.to_csv(full_table_path, index=False)
    logger.info(f"Saved full comparison table to {full_table_path}")
    
    # Create pivot tables if possible
    if len(df["chunking"].unique()) > 1 and len(df["embedding"].unique()) > 1:
        # Faithfulness table
        f_pivot = df.pivot_table(index="chunking", columns="embedding", values="faithfulness")
        f_pivot_path = os.path.join(output_dir, "faithfulness_by_type.csv")
        f_pivot.to_csv(f_pivot_path)
        logger.info(f"Saved faithfulness pivot table to {f_pivot_path}")
        
        # Accuracy table
        a_pivot = df.pivot_table(index="chunking", columns="embedding", values="accuracy") 
        a_pivot_path = os.path.join(output_dir, "accuracy_by_type.csv")
        a_pivot.to_csv(a_pivot_path)
        logger.info(f"Saved accuracy pivot table to {a_pivot_path}")
        
        # Combined table
        c_pivot = df.pivot_table(index="chunking", columns="embedding", values="combined")
        c_pivot_path = os.path.join(output_dir, "combined_by_type.csv")
        c_pivot.to_csv(c_pivot_path)
        logger.info(f"Saved combined score pivot table to {c_pivot_path}")

def parse_arguments():
    """Parse command line arguments."""
    parser = argparse.ArgumentParser(description="Response Quality Evaluator")
    
    parser.add_argument("--answers_dir", type=str, required=True,
                       help="Directory containing answer JSON files")
    parser.add_argument("--output_dir", type=str, default=None,
                       help="Directory to store evaluation results")
    parser.add_argument("--retrieval_dir", type=str, default=None,
                       help="Directory containing retrieval results")
    parser.add_argument("--ground_truth", type=str, required=True,
                       help="Path to ground truth JSON file")
    parser.add_argument("--top_k", type=int, default=None,
                       help="Number of top chunks to consider (default: all)")
    parser.add_argument("--threads", type=int, default=4,
                       help="Number of parallel threads to use")
    parser.add_argument("--use_gpu", action="store_true",
                       help="Use GPU for NLP processing if available")
    
    return parser.parse_args()

def main():
    """Main execution function."""
    # Parse arguments
    args = parse_arguments()
    
    # Set default output directory if not specified
    if args.output_dir is None:
        args.output_dir = os.path.join(args.answers_dir, "evaluations")
    
    # Set default retrieval directory if not specified
    if args.retrieval_dir is None:
        answers_parent = os.path.dirname(args.answers_dir)
        if os.path.basename(answers_parent).startswith("run_"):
            args.retrieval_dir = answers_parent
    
    # Create output directory
    os.makedirs(args.output_dir, exist_ok=True)
    
    # Initialize evaluator
    evaluator = ResponseQualityEvaluator(use_gpu=args.use_gpu)
    
    # Load data
    ground_truth = evaluator.load_ground_truth(args.ground_truth)
    answers = evaluator.load_answers(args.answers_dir)
    retrieval_results = evaluator.load_retrieval_results(args.retrieval_dir)
    
    # Check if we have data
    if not ground_truth:
        logger.error("No ground truth data loaded")
        return
    
    if not answers:
        logger.error("No answer data loaded")
        return
    
    if not retrieval_results:
        logger.error("No retrieval results loaded")
        return
    
    # Log loaded data stats
    logger.info(f"Loaded data for evaluation:")
    logger.info(f"  Ground Truth: {len(ground_truth)} queries")
    logger.info(f"  Answers: {len(answers)} retrievers")
    logger.info(f"  Retrieval Results: {len(retrieval_results)} retrievers")
    
    # Print first ground truth item for debugging
    if ground_truth:
        first_key = next(iter(ground_truth))
        logger.info(f"Sample ground truth for {first_key}: {ground_truth[first_key][:100]}...")
    
    # Evaluate each retriever
    evaluation_results = {}
    
    for retriever_name, retriever_answers in answers.items():
        # Skip if missing retrieval results
        if retriever_name not in retrieval_results:
            logger.warning(f"Skipping {retriever_name} - no retrieval results found")
            continue
        
        # Evaluate
        results = evaluator.evaluate_retriever(
            retriever_name=retriever_name,
            answers=retriever_answers,
            retrieval_results=retrieval_results[retriever_name],
            ground_truth=ground_truth,
            top_k=args.top_k
        )
        
        # Store results
        evaluation_results[retriever_name] = results
        
        # Save individual results
        output_path = os.path.join(args.output_dir, f"{retriever_name.replace(' ', '_')}_evaluation.json")
        with open(output_path, 'w', encoding='utf-8') as f:
            json.dump(results, f, indent=2)
        
        logger.info(f"Saved evaluation results for {retriever_name} to {output_path}")
    
    # Compare retrievers
    comparison = evaluator.compare_retrievers(evaluation_results)
    
    # Save comparison
    comparison_path = os.path.join(args.output_dir, "retriever_comparison.json")
    with open(comparison_path, 'w', encoding='utf-8') as f:
        json.dump(comparison, f, indent=2)
    
    logger.info(f"Saved retriever comparison to {comparison_path}")
    
    # Create comparison tables
    create_comparison_tables(comparison, args.output_dir)
    
    # Print summary
    logger.info("Evaluation summary:")
    for retriever, result in evaluation_results.items():
        logger.info(f"  {retriever}:")
        logger.info(f"    Faithfulness: {result['avg_faithfulness']:.4f}")
        logger.info(f"    Accuracy: {result['avg_accuracy']:.4f}")
    
    logger.info("Evaluation completed successfully")

if __name__ == "__main__":
    main()